bool Sounds::validateJsonForCreation(const Json::Value &pJson, std::string &err)
{
    if(pJson.isMember("id"))
    {
        if(!validJsonOfField(0, "id", pJson["id"], err, true))
            return false;
    }
    if(pJson.isMember("user_id"))
    {
        if(!validJsonOfField(1, "user_id", pJson["user_id"], err, true))
            return false;
    }
    else
    {
        err="The user_id column cannot be null";
        return false;
    }
    if(pJson.isMember("filename"))
    {
        if(!validJsonOfField(2, "filename", pJson["filename"], err, true))
            return false;
    }
    else
    {
        err="The filename column cannot be null";
        return false;
    }
    if(pJson.isMember("original_name"))
    {
        if(!validJsonOfField(3, "original_name", pJson["original_name"], err, true))
            return false;
    }
    else
    {
        err="The original_name column cannot be null";
        return false;
    }
    if(pJson.isMember("file_path"))
    {
        if(!validJsonOfField(4, "file_path", pJson["file_path"], err, true))
            return false;
    }
    else
    {
        err="The file_path column cannot be null";
        return false;
    }
    if(pJson.isMember("file_size"))
    {
        if(!validJsonOfField(5, "file_size", pJson["file_size"], err, true))
            return false;
    }
    else
    {
        err="The file_size column cannot be null";
        return false;
    }
    if(pJson.isMember("mime_type"))
    {
        if(!validJsonOfField(6, "mime_type", pJson["mime_type"], err, true))
            return false;
    }
    else
    {
        err="The mime_type column cannot be null";
        return false;
    }
    if(pJson.isMember("duration_seconds"))
    {
        if(!validJsonOfField(7, "duration_seconds", pJson["duration_seconds"], err, true))
            return false;
    }
    else
    {
        err="The duration_seconds column cannot be null";
        return false;
    }
    if(pJson.isMember("created_at"))
    {
        if(!validJsonOfField(8, "created_at", pJson["created_at"], err, true))
            return false;
    }
    if(pJson.isMember("updated_at"))
    {
        if(!validJsonOfField(9, "updated_at", pJson["updated_at"], err, true))
            return false;
    }
    return true;
}
